import React, { useState, useEffect } from 'react';
import './App.css';

const MENU = [
  { id: 1, name: 'Эспрессо', price: 150, icon: '☕' },
  { id: 2, name: 'Круассан', price: 200, icon: '🥐' }
];

function App() {
  const [orders, setOrders] = useState([]); // История заказов
  const [activeOrder, setActiveOrder] = useState(null);

  // Загрузка истории
  const fetchHistory = () => {
    fetch('http://localhost:8000/index.php')
      .then(res => res.json())
      .then(data => setOrders(data));
  };

  useEffect(() => {
    fetchHistory();
    const interval = setInterval(fetchHistory, 3000); // Опрос сервера
    return () => clearInterval(interval);
  }, []);

  const placeOrder = async (item) => {
    const res = await fetch('http://localhost:8000/index.php', {
      method: 'POST',
      body: JSON.stringify({ description: item.name, total_amount: item.price })
    });
    const newOrder = await res.json();
    setActiveOrder(newOrder.id);
    fetchHistory();
  };

  return (
    <div className="app-container">
      <h1 className="logo">ETIKA GUEST</h1>

      <section className="menu">
        <h3>Меню</h3>
        <div className="menu-grid">
          {MENU.map(item => (
            <div key={item.id} className="menu-item" onClick={() => placeOrder(item)}>
              <span className="icon">{item.icon}</span>
              <p>{item.name} — {item.price}₽</p>
            </div>
          ))}
        </div>
      </section>

      <section className="history">
        <h3>Личный кабинет / Мои заказы</h3>
        <div className="orders-list">
          {orders.map(o => (
            <div key={o.id} className={`order-card ${o.status === 'Готов' ? 'ready' : ''}`}>
              <span>Заказ #{o.id}: {o.description}</span>
              <strong className="status-label">{o.status}</strong>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
}

export default App;
